[LANG] Java [FRAMEWORK] Spring Boot [METHOD] GET [PATH] /api/event_items [CODE] @RestController
@RequestMapping("/api/event_items")
@PreAuthorize("isAuthenticated()")
public class EventController {
    @GetMapping
    public Page<EventDTO> list(@AuthenticationPrincipal User user, Pageable pageable) {
        return repo.findByOwnerId(user.getId(), pageable).map(mapper::toDto);
    }

    @PostMapping
    public ResponseEntity<EventDTO> create(@RequestBody @Valid EventCreateDTO dto, @AuthenticationPrincipal User user) {
        Event entity = mapper.toEntity(dto);
        entity.setOwnerId(user.getId());
        return ResponseEntity.status(201).body(mapper.toDto(repo.save(entity)));
    }
}

